/** Returns states for a given country code, or [] if none defined */
export function getStates(countryCode) {
  return STATES_BY_COUNTRY[countryCode] || [];
}

/** Returns city list for a state (or country fallback), or [] if none */
export function getCities(countryCode, stateCode) {
  if (stateCode && CITIES_BY_STATE[countryCode]?.[stateCode]) {
    return CITIES_BY_STATE[countryCode][stateCode];
  }
  if (CITIES_BY_COUNTRY[countryCode]) return CITIES_BY_COUNTRY[countryCode];
  return [];
}
